import 'package:equatable/equatable.dart'; enum TransferDirection { upload, download } enum TransferStatus { pending, inProgress, paused, completed, failed } class FileEntity extends Equatable { final String fileId; final String fileName; final int fileSizeBytes; final String mimeType; final TransferDirection direction; final TransferStatus status; final int bytesTransferred; final String? localPath; const FileEntity({required this.fileId, required this.fileName, required this.fileSizeBytes, required this.mimeType, required this.direction, this.status = TransferStatus.pending, this.bytesTransferred = 0, this.localPath}); @override List<Object?> get props => [fileId, status]; double get progress => fileSizeBytes > 0 ? (bytesTransferred / fileSizeBytes).clamp(0.0, 1.0) : 0.0; }
